53	/* RFC 9002, 6.2.2.  Handshakes and New Paths: kInitialRtt */
54	#define NGX_QUIC_INITIAL_RTT                 333 /* ms */
55	
56	#define NGX_QUIC_UNSET_PN                    (uint64_t) -1
57	
58	/*  0-RTT and 1-RTT data exist in the same packet number space,
59	 *  so we have 3 packet number spaces:
60	 *
61	 *  0 - Initial
62	 *  1 - Handshake
63	 *  2 - 0-RTT and 1-RTT
64	 */
65	#define ngx_quic_get_send_ctx(qc, level)                                      \
66	    ((level) == NGX_QUIC_ENCRYPTION_INITIAL) ? &((qc)->send_ctx[0])           \
67	        : (((level) == NGX_QUIC_ENCRYPTION_HANDSHAKE) ? &((qc)->send_ctx[1])  \
68	                                                      : &((qc)->send_ctx[2]))
69	
70	#define ngx_quic_get_connection(c)                                            \
71	    (((c)->udp) ? (((ngx_quic_socket_t *)((c)->udp))->quic) : NULL)
72	
73	#define ngx_quic_get_socket(c)               ((ngx_quic_socket_t *)((c)->udp))
74	
75	#define ngx_quic_init_rtt(qc)                                                 \
76	    (qc)->avg_rtt = NGX_QUIC_INITIAL_RTT;                                     \
77	    (qc)->rttvar = NGX_QUIC_INITIAL_RTT / 2;                                  \
78	    (qc)->min_rtt = NGX_TIMER_INFINITE;                                       \
79	    (qc)->first_rtt = NGX_TIMER_INFINITE;                                     \
80	    (qc)->latest_rtt = 0;
81	
82	
83	typedef enum {
84	    NGX_QUIC_PATH_IDLE = 0,
85	    NGX_QUIC_PATH_VALIDATING,
86	    NGX_QUIC_PATH_WAITING,
87	    NGX_QUIC_PATH_MTUD
88	} ngx_quic_path_state_e;
89	
