189	/*
190	 * RFC 9000, 12.3.  Packet Numbers
191	 *
192	 *  Conceptually, a packet number space is the context in which a packet
193	 *  can be processed and acknowledged.  Initial packets can only be sent
194	 *  with Initial packet protection keys and acknowledged in packets that
195	 *  are also Initial packets.
196	 */
197	struct ngx_quic_send_ctx_s {
198	    ngx_uint_t                        level;
199	
200	    ngx_quic_buffer_t                 crypto;
201	    uint64_t                          crypto_sent;
202	
203	    uint64_t                          pnum;        /* to be sent */
