206	
207	    ngx_queue_t                       frames;      /* generated frames */
208	    ngx_queue_t                       sending;     /* frames assigned to pkt */
209	    ngx_queue_t                       sent;        /* frames waiting ACK */
210	
211	    uint64_t                          pending_ack; /* non sent ack-eliciting */
212	    uint64_t                          largest_range;
213	    uint64_t                          first_range;
214	    ngx_msec_t                        largest_received;
215	    ngx_msec_t                        ack_delay_start;
216	    ngx_uint_t                        nranges;
217	    ngx_quic_ack_range_t              ranges[NGX_QUIC_MAX_RANGES];
