144	static ngx_inline u_char *
145	ngx_quic_parse_int(u_char *pos, u_char *end, uint64_t *out)
146	{
147	    u_char      *p;
148	    uint64_t     value;
149	    ngx_uint_t   len;
150	
151	    if (pos >= end) {
152	        return NULL;
153	    }
154	
155	    p = pos;
156	    len = 1 << (*p >> 6);
157	
158	    value = *p++ & 0x3f;
159	
160	    if ((size_t)(end - p) < (len - 1)) {
161	        return NULL;
162	    }
163	
164	    while (--len) {
165	        value = (value << 8) + *p++;
166	    }
167	
168	    *out = value;
169	
170	    return p;
171	}
