214	ngx_quic_copy_bytes(u_char *pos, u_char *end, size_t len, u_char *dst)
215	{
216	    if ((size_t)(end - pos) < len) {
217	        return NULL;
218	    }
219	
220	    ngx_memcpy(dst, pos, len);
221	
222	    return pos + len;
223	}
