226	static ngx_inline ngx_uint_t
227	ngx_quic_varint_len(uint64_t value)
228	{
229	    if (value < (1 << 6)) {
230	        return 1;
231	    }
232	
233	    if (value < (1 << 14)) {
234	        return 2;
235	    }
236	
237	    if (value < (1 << 30)) {
238	        return 4;
239	    }
240	
241	    return 8;
242	}
