328	            ngx_log_debug4(NGX_LOG_DEBUG_EVENT, log, 0,
329	                           "*%uA quic recvmsg: %V fd:%d n:%z",
330	                           c->number, &addr, c->fd, n);
331	        }
332	
333	        }
334	#endif
335	
336	        log->data = NULL;
337	        log->handler = NULL;
