352	ngx_quic_close_accepted_connection(ngx_connection_t *c)
353	{
354	    ngx_free_connection(c);
355	
356	    c->fd = (ngx_socket_t) -1;
357	
358	    if (c->pool) {
359	        ngx_destroy_pool(c->pool);
360	    }
361	
