368	static ngx_connection_t *
369	ngx_quic_lookup_connection(ngx_listening_t *ls, ngx_str_t *key,
370	    struct sockaddr *local_sockaddr, socklen_t local_socklen)
371	{
372	    uint32_t            hash;
373	    ngx_int_t           rc;
374	    ngx_connection_t   *c;
375	    ngx_rbtree_node_t  *node, *sentinel;
376	    ngx_quic_socket_t  *qsock;
377	
378	    if (key->len == 0) {
379	        return NULL;
380	    }
381	
382	    node = ls->rbtree.root;
383	    sentinel = ls->rbtree.sentinel;
384	    hash = ngx_crc32_long(key->data, key->len);
385	
